using System.Collections;
using System.Collections.Generic;
using UnityEngine;

// Novas ações de diálogo (Etapa 5.3) — itens com quantidade, missões e branch
// condicional. Aparecem automaticamente no "+ Adicionar Ação".

/// <summary>Remove uma quantidade de um item do inventário do player (Etapa 4.2 — ex: entregar item de missão a um NPC).</summary>
[System.Serializable]
public class Action_RemoveItem : NpcAction
{
    public ItemData item;

    [Min(1)] public int amount = 1;

    [Tooltip("Se o item removido for o item equipado e a quantidade chegar a 0, também o desequipa.")]
    public bool unequipIfDepleted = true;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || item == null) yield break;

        progress.RemoveItem(item, amount);

        if (unequipIfDepleted && progress.GetItemQuantity(item) <= 0 && progress.HasItemEquipped(item))
            progress.EquipItem(null);
    }
}

/// <summary>Inicia uma missão (Etapa 5.1 — escreve a variável global de activação via MissionManager).</summary>
[System.Serializable]
public class Action_StartMission : NpcAction
{
    public MissionData mission;

    public override IEnumerator Execute(NpcController npc)
    {
        MissionManager.Instance?.StartMission(mission);
        yield break;
    }
}

/// <summary>Conclui uma missão (Etapa 5.1 — escreve a variável global de conclusão via MissionManager).</summary>
[System.Serializable]
public class Action_CompleteMission : NpcAction
{
    public MissionData mission;

    public override IEnumerator Execute(NpcController npc)
    {
        MissionManager.Instance?.CompleteMission(mission);
        yield break;
    }
}

/// <summary>
/// Marca uma tarefa de uma missão como concluída (Sistema de Missões — Missão >
/// Tarefa; tarefas não-lineares — ver MissionTask.dependsOnTaskIds). Usa-se em
/// qualquer evento de NPC (diálogo) ou de objecto (ex: ao recolher um item, num
/// evento "OnPickup"/"OnInteract") para marcar que essa tarefa específica foi
/// feita. Não precisa de ser "a próxima" tarefa de uma sequência: pode ser
/// qualquer tarefa da missão (ex: "interagir com X" e "interagir com Y", em
/// qualquer ordem, ambas necessárias para desbloquear uma terceira tarefa).
/// Quando TODAS as tarefas da missão ficarem concluídas, a missão é concluída
/// automaticamente (banner/música "MISSÃO CONCLUÍDA").
/// </summary>
[System.Serializable]
public class Action_CompleteMissionTask : NpcAction
{
    public MissionData mission;

    [Tooltip("\"Task Id\" da tarefa a marcar como concluída (ver MissionTask.taskId — se vazio nessa tarefa, o id efectivo é \"tarefa_<índice>\", 0 = primeira).")]
    public string taskId;

    public override IEnumerator Execute(NpcController npc)
    {
        MissionManager.Instance?.CompleteTask(mission, taskId);
        yield break;
    }
}

/// <summary>
/// Define directamente o estado "concluída" (verdadeiro/falso) de uma tarefa
/// pelo seu "Task Id" — útil para ramos de diálogo que "saltam" tarefas (ex: o
/// jogador já tinha feito algo antes de a missão começar) ou que precisam de
/// "desfazer" o progresso de uma tarefa. Marcar como concluída pode concluir a
/// missão automaticamente, se essa for a última tarefa em falta.
/// </summary>
[System.Serializable]
public class Action_SetMissionTaskState : NpcAction
{
    public MissionData mission;

    [Tooltip("\"Task Id\" da tarefa a alterar (ver MissionTask.taskId — se vazio nessa tarefa, o id efectivo é \"tarefa_<índice>\", 0 = primeira).")]
    public string taskId;

    [Tooltip("Novo estado \"concluída\" desta tarefa.")]
    public bool completed = true;

    public override IEnumerator Execute(NpcController npc)
    {
        MissionManager.Instance?.SetTaskCompleted(mission, taskId, completed);
        yield break;
    }
}

/// <summary>
/// Branch condicional (Etapa 5.3): avalia uma lista de NpcCondition e activa
/// "eventIdIfTrue" se for verdadeira (ou "eventIdIfFalse" caso contrário), via
/// ActivateEventById — cobre "executar evento X se condição verdadeira /
/// evento Y se falsa". O evento activado dispara naturalmente no próximo
/// Update/Touch/Button (sem reentrância).
/// </summary>
[System.Serializable]
public class Action_ConditionalBranch : NpcAction
{
    [Tooltip("Condições a avaliar (lista vazia = verdadeiro).")]
    [SerializeReference] public List<NpcCondition> conditions = new List<NpcCondition>();

    [Tooltip("Se activo, TODAS as condições têm de se cumprir; senão, basta UMA.")]
    public bool requireAll = true;

    [Tooltip("EventId a activar se a avaliação for verdadeira (vazio = nada).")]
    public string eventIdIfTrue = "";

    [Tooltip("EventId a activar se a avaliação for falsa (vazio = nada).")]
    public string eventIdIfFalse = "";

    public override IEnumerator Execute(NpcController npc)
    {
        bool result = NpcConditionUtil.EvaluateConditions(conditions, requireAll, npc);

        string eventId = result ? eventIdIfTrue : eventIdIfFalse;
        if (!string.IsNullOrEmpty(eventId))
            npc.ActivateEventById(eventId);

        yield break;
    }
}
